local function send_json_response(status, data)
    ngx.status = status
    ngx.header["Content-Type"] = "application/json; charset=utf-8"
    ngx.header["X-Content-Type-Options"] = "nosniff"
    ngx.header["Cache-Control"] = "no-store, no-cache"
    ngx.say(cjson.encode(data))
    return ngx.exit(status)
end

local function send_error(status, message)
    return send_json_response(status, { success = false, error = message })
end

local function validate_api_key()
    local expected_key = os.getenv("REDIS_API_KEY")
    if not expected_key or expected_key == "" then
        ngx.log(ngx.WARN, "REDIS_API_KEY not configured, denying all requests")
        return false
    end

    local provided_key = ngx.req.get_headers()["X-API-Key"]
    if not provided_key then
        return false
    end

    -- Constant-time comparison to prevent timing attacks
    if #provided_key ~= #expected_key then
        return false
    end

    local result = 0
    for i = 1, #expected_key do
        result = bit.bor(result, bit.bxor(string.byte(expected_key, i), string.byte(provided_key, i)))
    end

    return result == 0
end

local function sanitize_string(s)
    if type(s) ~= "string" then
        return nil
    end
    -- Remove null bytes
    s = s:gsub("%z", "")
    return s
end

local function validate_key_pattern(pattern)
    if not pattern or type(pattern) ~= "string" then
        return false
    end
    if #pattern > MAX_KEYS_PATTERN_LENGTH then
        return false
    end
    -- Prevent overly broad patterns that could cause performance issues
    if pattern == "*" then
        return false
    end
    return true
end

local function validate_command(cmd)
    if not cmd or type(cmd) ~= "string" then
        return false, "Command must be a non-empty string"
    end

    cmd = string.lower(sanitize_string(cmd))

    if BLOCKED_COMMANDS[cmd] then
        return false, "Command '" .. cmd .. "' is blocked for security reasons"
    end

    if not ALLOWED_COMMANDS[cmd] then
        return false, "Command '" .. cmd .. "' is not in the allowed commands list"
    end

    return true, cmd
end

local function validate_args(args)
    if not args then
        return true, {}
    end

    if type(args) ~= "table" then
        return false, "Arguments must be an array"
    end

    if #args > MAX_ARGS then
        return false, "Too many arguments (max " .. MAX_ARGS .. ")"
    end

    local sanitized = {}
    for i, arg in ipairs(args) do
        if type(arg) == "string" then
            if #arg > MAX_ARG_LENGTH then
                return false, "Argument " .. i .. " exceeds maximum length"
            end
            sanitized[i] = sanitize_string(arg)
        elseif type(arg) == "number" then
            sanitized[i] = tostring(arg)
        else
            return false, "Argument " .. i .. " has invalid type: " .. type(arg)
        end
    end

    return true, sanitized
end

local function connect_redis()
    local red = redis:new()
    red:set_timeout(REDIS_TIMEOUT)

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        return nil, "Failed to connect to Redis: " .. (err or "unknown error")
    end

    if REDIS_PASSWORD and REDIS_PASSWORD ~= "" then
        local res, err = red:auth(REDIS_PASSWORD)
        if not res then
            red:close()
            return nil, "Redis authentication failed: " .. (err or "unknown error")
        end
    end

    return red, nil
end

local function close_redis(red)
    if not red then
        return
    end
    local ok, err = red:set_keepalive(REDIS_KEEPALIVE_TIMEOUT, REDIS_KEEPALIVE_POOL_SIZE)
    if not ok then
        ngx.log(ngx.WARN, "Failed to set Redis keepalive: ", err)
        red:close()
    end
end

local function format_redis_result(result)
    if type(result) == "table" then
        -- Check if it's a Redis array/bulk reply
        local formatted = {}
        for i, v in ipairs(result) do
            if type(v) == "userdata" then
                -- ngx.null
                formatted[i] = cjson.null
            else
                formatted[i] = v
            end
        end
        return formatted
    elseif type(result) == "userdata" then
        return cjson.null
    else
        return result
    end
end

local function execute_command(red, cmd, args)
    cmd = string.lower(cmd)

    -- Special handling for keys command to prevent broad patterns
    if cmd == "keys" then
        if #args < 1 then
            return nil, "KEYS command requires a pattern argument"
        end
        if not validate_key_pattern(args[1]) then
            return nil, "Invalid or overly broad key pattern. Use SCAN instead of KEYS with '*'"
        end
    end

    -- Special handling for eval
    if cmd == "eval" then
        if #args < 2 then
            return nil, "EVAL requires at least script and numkeys arguments"
        end
        local script = args[1]
        if #script > MAX_EVAL_SCRIPT_LENGTH then
            return nil, "Eval script exceeds maximum allowed length"
        end
        local numkeys = tonumber(args[2])
        if not numkeys or numkeys < 0 or numkeys > MAX_ARGS then
            return nil, "Invalid numkeys value for EVAL"
        end
        if (#args - 2) < numkeys then
            return nil, "Not enough keys provided for EVAL"
        end
        local res, err = red:eval(unpack(args))
        if not res then
            return nil, err
        end
        return format_redis_result(res), nil
    end

    -- Execute the command dynamically
    local redis_func = red[cmd]
    if not redis_func then
        return nil, "Redis command method not found: " .. cmd
    end

    local res, err
    if #args == 0 then
        res, err = redis_func(red)
    else
        res, err = redis_func(red, unpack(args))
    end

    if not res then
        return nil, err
    end

    return format_redis_result(res), nil
end

local function handle_request()
    -- Only allow POST requests
    if ngx.req.get_method() ~= "POST" then
        return send_error(405, "Method not allowed. Use POST.")
    end

    -- Validate API key
    if not validate_api_key() then
        return send_error(401, "Unauthorized. Provide a valid X-API-Key header.")
    end

    -- Rate limiting using shared dict (requires lua_shared_dict in nginx.conf)
    local limit = ngx.shared.redis_api_limit
    if limit then
        local client_ip = ngx.var.remote_addr
        local key = "rate:" .. client_ip
        local count, err = limit:incr(key, 1, 0, 60)
        if count and count > 100 then
            return send_error(429, "Rate limit exceeded. Max 100 requests per minute.")
        end
    end

    -- Read and parse request body
    ngx.req.read_body()
    local body = ngx.req.get_body_data()
    if not body then
        return send_error(400, "Request body is required")
    end

    -- Limit body size
    if #body > 65536 then
        return send_error(413, "Request body too large")
    end

    local ok, request = pcall(cjson.decode, body)
    if not ok or type(request) ~= "table" then
        return send_error(400, "Invalid JSON in request body")
    end

    -- Support single command or batch commands
    local commands = {}
    if request.command then
        -- Single command mode
        commands = { { command = request.command, args = request.args } }
    elseif request.commands and type(request.commands) == "table" then
        -- Batch mode
        if #request.commands > 20 then
            return send_error(400, "Maximum 20 commands per batch request")
        end
        commands = request.commands
    else
        return send_error(400, "Request must contain 'command' or 'commands' field")
    end

    -- Validate all commands before executing any
    local validated_commands = {}
    for i, cmd_entry in ipairs(commands) do
        if type(cmd_entry) ~= "table" then
            return send_error(400, "Command entry " .. i .. " must be an object")
        end

        local valid, cmd_or_err = validate_command(cmd_entry.command)
        if not valid then
            return send_error(400, "Command " .. i .. ": " .. cmd_or_err)
        end

        local args_valid, args_or_err = validate_args(cmd_entry.args)
        if not args_valid then
            return send_error(400, "Command " .. i .. ": " .. args_or_err)
        end

        validated_commands[i] = { command = cmd_or_err, args = args_or_err }
    end

    -- Connect to Redis
    local red, conn_err = connect_redis()
    if not red then
        ngx.log(ngx.ERR, "Redis connection error: ", conn_err)
        return send_error(503, "Redis service unavailable")
    end

    -- Execute commands
    local results = {}
    local has_error = false

    for i, cmd_entry in ipairs(validated_commands) do
        local result, err = execute_command(red, cmd_entry.command, cmd_entry.args)
        if err then
            results[i] = {
                command = cmd_entry.command,
                success = false,
                error = err
            }
            has_error = true
            ngx.log(ngx.WARN, "Redis command error: ", cmd_entry.command, " - ", err)
        else
            results[i] = {
                command = cmd_entry.command,
                success = true,
                result = result
            }
        end
    end

    -- Return connection to pool
    close_redis(red)

    -- Log the request (without sensitive data)
    local cmd_names = {}
    for i, c in ipairs(validated_commands) do
        cmd_names[i] = c.command
    end
    ngx.log(ngx.INFO, "Redis API request from ", ngx.var.remote_addr,
        " commands: ", table.concat(cmd_names, ", "))

    -- Build response
    local response
    if #results == 1 then
        response = results[1]
    else
        response = {
            success = not has_error,
            results = results
        }
    end

    local status = has_error and 422 or 200
    return send_json_response(status, response)
end

-- Health check endpoint
local function handle_health()
    if ngx.req.get_method() ~= "GET" then
        return send_error(405, "Method not allowed")
    end

    local red, err = connect_redis()
    if not red then
        return send_json_response(503, { status = "unhealthy", error = "Cannot connect to Redis" })
    end

    local res, err = red:ping()
    close_redis(red)

    if not res then
        return send_json_response(503, { status = "unhealthy", error = "Redis ping failed" })
    end

    return send_json_response(200, { status = "healthy", redis = "connected" })
end

-- List allowed commands endpoint
local function handle_commands_list()
    if ngx.req.get_method() ~= "GET" then
        return send_error(405, "Method not allowed")
    end

    if not validate_api_key() then
        return send_error(401, "Unauthorized")
    end

    local cmds = {}
    for cmd, _ in pairs(ALLOWED_COMMANDS) do
        cmds[#cmds + 1] = cmd
    end
    table.sort(cmds)

    return send_json_response(200, { allowed_commands = cmds })
end

-- Route requests
local uri = ngx.var.uri

if uri == "/health" or uri == "/healthz" then
    return handle_health()
elseif uri == "/commands" then
    return handle_commands_list()
elseif uri == "/execute" or uri == "/" then
    return handle_request()
else
    return send_error(404, "Not found")
end